def binary_search_increasing(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def binary_search_decreasing(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            high = mid - 1
        else:
            low = mid + 1
    return -1

def find_peak_element(arr):
    n = len(arr)
    if n == 0:
        return -1
    if n == 1:
        return 0

    low = 0
    high = n - 1

    while low < high:
        mid = low + (high - low) // 2
        if arr[mid] < arr[mid + 1]:
            low = mid + 1
        else:
            high = mid
    return low

def search_in_bitonic_array(arr, target):
    n = len(arr)
    if n == 0:
        return -1

    peak_index = find_peak_element(arr)

    if arr[peak_index] == target:
        return peak_index

    result_increasing = binary_search_increasing(arr, target, 0, peak_index - 1)
    if result_increasing != -1:
        return result_increasing

    result_decreasing = binary_search_decreasing(arr, target, peak_index + 1, n - 1)
    if result_decreasing != -1:
        return result_decreasing

    return -1
